import React from "react";
import { safeGet, safeArray, safeObject } from "../utils/helpers";

const BillContent = ({ data, titleSuffix = "" }) => {
  const header = safeObject(data.header);

  // FIX: Handle truthy empty array [] from legacy items column
  let rawItems = data.items_json;
  if (!rawItems || rawItems.length === 0) {
    rawItems = data.items;
  }
  const items = safeArray(rawItems);

  const billNumber = safeGet(header, "bill_number") || safeGet(data, "bill_number", "N/A");
  const tableNo = safeGet(header, "table_no") || safeGet(data, "table_no", "N/A");
  const hotelName = safeGet(data, "hotel_name", "Restaurant");
  const address = safeGet(data, "address", "");
  const phone = safeGet(data, "phone", "");
  const gstin = safeGet(data, "gstin", "");
  const createdAt = safeGet(data, "created_at") || safeGet(data, "bill_date", null);
  const subtotal = safeGet(data, "subtotal", 0);
  const sgst = safeGet(data, "sgst", 0);
  const cgst = safeGet(data, "cgst", 0);
  const grandTotal = safeGet(data, "grand_total", 0);

  return (
    <div
      style={{
        display: "block",
        position: "static",
        clear: "both",
        float: "none",
        fontFamily: "monospace",
        fontSize: "14px",
        width: "300px",
        maxWidth: "100%",
        color: "black",
        background: "yellow",  // BRIGHT DEBUG COLOR
        border: "5px solid red",  // VISIBLE BORDER
        padding: "20px",
        marginBottom: "30px",
        pageBreakInside: "avoid"
      }}
    >
      <div style={{ fontSize: "20px", fontWeight: "bold", background: "lime", padding: "10px" }}>
        {hotelName} {titleSuffix} - TEST VISIBLE
      </div>
      {address && <div className="text-center text-xs">{address}</div>}
      <div className="text-center text-xs">
        GST Included{gstin ? ` GSTIN: ${gstin} ` : ""}
        {phone ? `  Ph: ${phone} ` : ""}
      </div>
      <div className="text-center">{"=".repeat(40)}</div>
      <div className="flex justify-between">
        <span>Bill No</span>
        <span>{billNumber}</span>
      </div>
      <div className="flex justify-between">
        <span>Date</span>
        <span>{createdAt ? new Date(createdAt).toLocaleString() : "N/A"}</span>
      </div>
      <div className="flex justify-between">
        <span>Table</span>
        <span>{tableNo}</span>
      </div>
      <div>{"=".repeat(40)}</div>

      <table className="w-full" style={{ width: "100%", color: "black" }}>
        <thead>
          <tr>
            <th className="text-left">No.</th>
            <th className="text-left">Item</th>
            <th className="text-left">Qty</th>
            <th className="text-left">Amt</th>
          </tr>
        </thead>
        <tbody>
          {items.length === 0 ? (
            <tr>
              <td colSpan="4" className="text-center">
                No Items Found
              </td>
            </tr>
          ) : (
            items.map((item, i) => {
              if (!item) {
                return (
                  <tr key={i} style={{ background: 'red' }}>
                    <td colSpan="4">CORRUPTED ITEM (NULL)</td>
                  </tr>
                );
              }
              // Standardize item properties
              let itemName = item.item_name || item.name || "Unknown Item";

              // Handle object names or JSON strings
              if (typeof itemName === "object") {
                itemName = itemName.name || itemName.item_name || JSON.stringify(itemName);
              }
              if (typeof itemName === "string" && (itemName.startsWith("[") || itemName.startsWith("{"))) {
                try {
                  const parsed = JSON.parse(itemName);
                  if (Array.isArray(parsed) && parsed.length > 0) itemName = parsed[0].name || parsed[0].item_name;
                  else if (typeof parsed === "object") itemName = parsed.name || parsed.item_name;
                } catch (e) { /* ignore */ }
              }

              let quantity = item.quantity || item.qty || 0;
              const lineTotal = item.line_total || item.amount || 0;

              // Fallback for missing/zero quantity but valid price (unlikely but possible)
              if (!quantity && lineTotal) quantity = 1;

              return (
                <tr key={i}>
                  <td>{i + 1}</td>
                  <td>{itemName}</td>
                  <td>{quantity}</td>
                  <td>{Number(lineTotal).toFixed(2)}</td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>

      <div>{"=".repeat(40)}</div>
      <div className="flex justify-between">
        <span>Subtotal</span>
        <span> {Number(subtotal).toFixed(2)}</span>
      </div>
      <div className="flex justify-between">
        <span>SGST (2.5%)</span>
        <span> {Number(sgst).toFixed(2)}</span>
      </div>
      <div className="flex justify-between">
        <span>CGST (2.5%)</span>
        <span> {Number(cgst).toFixed(2)}</span>
      </div>
      <div className="flex justify-between font-bold">
        <span>Total</span>
        <span> {Math.round(Number(grandTotal)).toFixed(2)}</span>
      </div>
      <div className="text-center text-xs mt-2">Thank you! Visit again</div>
    </div>
  );
};

export default function BillPrint({ billData = null }) {
  const data =
    billData || (typeof window !== "undefined" && window.printBillData) || null;

  if (!data) {
    console.log("BillPrint: No bill data available");
    return <div>No bill data</div>;
  }

  if (data.split && data.bills) {
    return (
      <div style={{
        display: "block",
        position: "static",
        width: "100%",
        clear: "both",
        background: "pink",  // DEBUG COLOR
        padding: "20px"
      }}>
        <h1 style={{ background: "orange", padding: "10px" }}>SPLIT BILL MODE - {data.bills.length} bills</h1>
        {data.bills.map((bill, index) => (
          <div key={index} style={{
            display: "block",
            position: "static",
            clear: "both",
            float: "none",
            marginBottom: "50px",
            pageBreakInside: "avoid",
            width: "100%"
          }}>
            <BillContent data={bill} titleSuffix={bill.titleSuffix} />
            {index < data.bills.length - 1 && (
              <div style={{
                textAlign: "center",
                margin: "30px 0",
                borderBottom: "2px dashed black",
                paddingBottom: "15px",
                fontSize: "14px",
                fontWeight: "bold"
              }}>
                ✂ CUT HERE ✂
              </div>
            )}
          </div>
        ))}
      </div>
    );
  }
  return <BillContent data={data} />;
}
